param([ValidateSet("User", "Repo")][string]$Scope = "User", [string]$RepoPath = "")
$ErrorActionPreference = "Stop"; $SkillName = "minimal-html-web-design"; $SourceDir = [IO.Path]::GetFullPath((Split-Path -Parent $MyInvocation.MyCommand.Path))
function Copy-Skill([string]$Root) { $Destination = [IO.Path]::GetFullPath((Join-Path $Root $SkillName)); $Prefix = $SourceDir.TrimEnd([IO.Path]::DirectorySeparatorChar) + [IO.Path]::DirectorySeparatorChar; if ($Destination -eq $SourceDir -or $Destination.StartsWith($Prefix, [StringComparison]::OrdinalIgnoreCase)) { throw "Refusing a destination inside the source skill" }; New-Item -ItemType Directory -Force -Path $Root | Out-Null; $Staging = Join-Path $Root (".$SkillName.tmp." + [Guid]::NewGuid()); New-Item -ItemType Directory -Path $Staging | Out-Null; try { Get-ChildItem -LiteralPath $SourceDir -Force | Copy-Item -Destination $Staging -Recurse -Force; if (Test-Path -LiteralPath $Destination) { Remove-Item -LiteralPath $Destination -Recurse -Force }; Move-Item -LiteralPath $Staging -Destination $Destination } finally { if (Test-Path -LiteralPath $Staging) { Remove-Item -LiteralPath $Staging -Recurse -Force } }; Write-Host "Installed: $Destination" }
function Remove-Legacy([string]$Root) { $Destination = [IO.Path]::GetFullPath((Join-Path $Root $SkillName)); if (-not (Test-Path -LiteralPath $Destination)) { return }; if ($Destination -eq $SourceDir) { Write-Host "Retained active source: $Destination"; return }; Remove-Item -LiteralPath $Destination -Recurse -Force; Write-Host "Removed same-name legacy copy: $Destination" }
if ($Scope -eq "User") { if ([string]::IsNullOrWhiteSpace($HOME) -or -not (Test-Path -LiteralPath $HOME -PathType Container)) { throw "A valid user home is required" }; $Root = Join-Path $HOME ".agents\skills"; $Base = $HOME } else { if ([string]::IsNullOrWhiteSpace($RepoPath) -or -not (Test-Path -LiteralPath $RepoPath -PathType Container)) { throw "-RepoPath must be an existing directory" }; $Resolved = [IO.Path]::GetFullPath((Resolve-Path -LiteralPath $RepoPath).Path); if ($Resolved -eq [IO.Path]::GetPathRoot($Resolved)) { throw "Refusing filesystem root" }; $Root = Join-Path $Resolved ".agents\skills"; $Base = $Resolved }
Copy-Skill $Root; Remove-Legacy (Join-Path $Base ".codex\skills"); Remove-Legacy (Join-Path $Base ".claude\skills")
